61	/// Top-level clone driver.
62	///
63	/// - Resolves TARGET to a concrete clone source (URL or path).
64	/// - Determines destination dir name (`[NAME]` override or
65	///   `derive_name(TARGET)`).
66	/// - Pre-checks target dir doesn't exist.
67	/// - Dispatches to `clone_one` (POR) or `clone_dual` (code,bot).
68	pub fn clone_repo(args: &CloneArgs) -> Result<(), Box<dyn std::error::Error>> {
69	    log::debug!("clone: enter");
70	
71	    let parsed = parse_target(&args.target)?;
72	    let source = match parsed {
73	        Target::Url(u) => u,
74	        Target::OwnerName(o, n) => resolve_url(&format!("{o}/{n}")),
75	        Target::Path(p) => p.to_str().ok_or("path is not valid UTF-8")?.to_string(),
76	        Target::BareName(n) => {
77	            return Err(format!(
78	                "'{n}' is a bare name — clone has no config-driven defaults; \
79	                 use 'owner/{n}', a full URL, or './{n}' for a local path"
80	            )
81	            .into());
82	        }
83	    };
84	
85	    let name = match &args.name {
86	        Some(n) => n.clone(),
87	        None => derive_name(&args.target)?,
88	    };
89	    let parent_dir = std::env::current_dir()?;
90	    let project_dir = parent_dir.join(&name);
91	
92	    if project_dir.exists() {
93	        return Err(format!("'{}' already exists", project_dir.display()).into());
94	    }
95	
96	    if args.dry_run {
97	        info!("Dry run — would execute:");
98	        match args.scope {
99	            ScopeKind::Por => {
100	                info!("  1. jj git clone --colocate {source} {name}");
101	            }
102	            ScopeKind::CodeBot => {
103	                let session_source = derive_session_url(&source);
104	                info!("  1. jj git clone --colocate {source} {name}");
105	                info!("  2. jj git clone --colocate {session_source} {name}/.claude");
106	                info!("  3. Create Claude Code symlink");
107	            }
108	        }
109	        return Ok(());
110	    }
111	
112	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
113	
114	    match args.scope {
115	        ScopeKind::Por => {
116	            clone_one(&source, &project_dir, &parent_dir)?;
117	            info!("");
118	            info!("Done! Project cloned to {}", project_dir.display());
119	            info!("  Code repo: {}", project_dir.display());
120	        }
121	        ScopeKind::CodeBot => clone_dual(&source, &project_dir, &parent_dir)?,
122	    }
123	
124	    log::debug!("clone: exit");
125	    Ok(())
126	}
