//! `vc-x1 clone` — clone a repo (URL or local path) into a workspace.
//!
//! - `--scope=code,bot` (default): dual-repo layout — clones code,
//!   derives bot source (`<source>.claude`), clones bot into
//!   `<target>/.claude`, creates the Claude Code symlink. Both
//!   sides must succeed.
//! - `--scope=por`: single repo into `<target>`. No `.claude/`,
//!   no symlink.
//!
//! TARGET shapes (all routed through `parse_target`): URL,
//! `owner/name` shorthand, or a local path (`./X`, `/X`, `~/X`,
//! `.`, `..`). Path-form is symmetric with `git clone /local/bare.git`
//! — useful for fixtures and CI scratch dirs.
//!
//! `clone_one` and `clone_dual` are `pub(crate)` so init's `-3`
//! reshape can reuse them for the "URL exists → clone" preflight
//! path (per `notes/chores-08.md > init + clone redesign`).

use std::path::Path;

use clap::Args;
use log::info;

use crate::common::run;
use crate::options_flags::scope::{ScopeKind, parse_scope_kind};
use crate::symlink;
use crate::url::{Target, derive_name, derive_session_url, parse_target, resolve_url};

/// CLI args for `vc-x1 clone`.
#[derive(Args, Debug)]
pub struct CloneArgs {
    /// Source to clone — URL, owner/name shorthand, or local path.
    ///
    /// - URL: `git@host:owner/name(.git)?`, `https://...(.git)?`
    /// - owner/name shorthand: resolves to
    ///   `git@github.com:owner/name.git`
    /// - Local path: `./X`, `../X`, `/X`, `~/X`, `~`, `.`, `..`
    ///   (passed directly to `git clone`)
    #[arg(value_name = "TARGET", verbatim_doc_comment)]
    pub target: String,

    /// Destination dir name in cwd [default: derived from TARGET]
    #[arg(value_name = "NAME")]
    pub name: Option<String>,

    /// What to clone: `code,bot` (dual, default) or `por` (single).
    #[arg(
        long,
        short,
        value_name = "SCOPE",
        value_parser = parse_scope_kind,
        default_value = "code,bot"
    )]
    pub scope: ScopeKind,

    /// Dry run — show what would be done without executing.
    #[arg(long)]
    pub dry_run: bool,
}

/// Top-level clone driver.
///
/// - Resolves TARGET to a concrete clone source (URL or path).
/// - Determines destination dir name (`[NAME]` override or
///   `derive_name(TARGET)`).
/// - Pre-checks target dir doesn't exist.
/// - Dispatches to `clone_one` (POR) or `clone_dual` (code,bot).
pub fn clone_repo(args: &CloneArgs) -> Result<(), Box<dyn std::error::Error>> {
    log::debug!("clone: enter");

    let parsed = parse_target(&args.target)?;
    let source = match parsed {
        Target::Url(u) => u,
        Target::OwnerName(o, n) => resolve_url(&format!("{o}/{n}")),
        Target::Path(p) => p.to_str().ok_or("path is not valid UTF-8")?.to_string(),
        Target::BareName(n) => {
            return Err(format!(
                "'{n}' is a bare name — clone has no config-driven defaults; \
                 use 'owner/{n}', a full URL, or './{n}' for a local path"
            )
            .into());
        }
    };

    let name = match &args.name {
        Some(n) => n.clone(),
        None => derive_name(&args.target)?,
    };
    let parent_dir = std::env::current_dir()?;
    let project_dir = parent_dir.join(&name);

    if project_dir.exists() {
        return Err(format!("'{}' already exists", project_dir.display()).into());
    }

    if args.dry_run {
        info!("Dry run — would execute:");
        match args.scope {
            ScopeKind::Por => {
                info!("  1. jj git clone --colocate {source} {name}");
            }
            ScopeKind::CodeBot => {
                let session_source = derive_session_url(&source);
                info!("  1. jj git clone --colocate {source} {name}");
                info!("  2. jj git clone --colocate {session_source} {name}/.claude");
                info!("  3. Create Claude Code symlink");
            }
        }
        return Ok(());
    }

    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;

    match args.scope {
        ScopeKind::Por => {
            clone_one(&source, &project_dir, &parent_dir)?;
            info!("");
            info!("Done! Project cloned to {}", project_dir.display());
            info!("  Code repo: {}", project_dir.display());
        }
        ScopeKind::CodeBot => clone_dual(&source, &project_dir, &parent_dir)?,
    }

    log::debug!("clone: exit");
    Ok(())
}

/// Clone a single repo via `jj git clone --colocate` and verify
/// bookmark tracking.
///
/// - `source` is the clone source (URL or local path).
/// - `target_dir` is the destination working repo location.
/// - `parent_dir` is the cwd for the `jj git clone` subprocess.
///
/// `jj git clone --colocate` does git clone + jj init + automatic
/// bookmark tracking in one step (unlike colocate-after-bare-git-clone,
/// which needs explicit `jj bookmark track`). The `verify_tracking`
/// call asserts the post-clone state matches expectations.
pub(crate) fn clone_one(
    source: &str,
    target_dir: &Path,
    parent_dir: &Path,
) -> Result<(), Box<dyn std::error::Error>> {
    let target_str = target_dir
        .to_str()
        .ok_or("target path is not valid UTF-8")?;
    info!("Cloning {source} → {target_str}...");
    run(
        "jj",
        &["git", "clone", "--colocate", source, target_str],
        parent_dir,
    )?;
    crate::common::verify_tracking(target_dir, "main")?;
    Ok(())
}

/// Orchestrate a dual-repo clone: code via `clone_one`, bot via
/// `clone_one` (no graceful skip — `--scope=code,bot` requires
/// both sides; users who want code-only should use `--scope=por`),
/// then create the Claude Code symlink.
pub(crate) fn clone_dual(
    code_source: &str,
    target_dir: &Path,
    parent_dir: &Path,
) -> Result<(), Box<dyn std::error::Error>> {
    let session_source = derive_session_url(code_source);
    let session_dir = target_dir.join(".claude");

    clone_one(code_source, target_dir, parent_dir)?;
    clone_one(&session_source, &session_dir, target_dir)?;
    info!("Creating Claude Code symlink...");
    let sl = symlink::install(target_dir)?;

    info!("");
    info!("Done! Project cloned to {}", target_dir.display());
    info!("  Code repo:    {}", target_dir.display());
    info!("  Session repo: {}", session_dir.display());
    info!(
        "  Symlink:      {} -> {}",
        sl.symlink_path.display(),
        sl.abs_target.display()
    );

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::{Cli, Commands};
    use clap::Parser;

    fn parse(args: &[&str]) -> CloneArgs {
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
            Commands::Clone(a) => a,
            _ => panic!("expected Clone"),
        }
    }

    fn parse_err(args: &[&str]) -> String {
        Cli::try_parse_from(args).unwrap_err().to_string()
    }

    #[test]
    fn defaults() {
        let args = parse(&["vc-x1", "clone", "owner/repo"]);
        assert_eq!(args.target, "owner/repo");
        assert!(args.name.is_none());
        assert_eq!(args.scope, ScopeKind::CodeBot);
        assert!(!args.dry_run);
    }

    #[test]
    fn with_name() {
        let args = parse(&["vc-x1", "clone", "owner/repo", "my-dir"]);
        assert_eq!(args.target, "owner/repo");
        assert_eq!(args.name.as_deref(), Some("my-dir"));
    }

    #[test]
    fn all_opts() {
        let args = parse(&[
            "vc-x1",
            "clone",
            "owner/repo",
            "my-dir",
            "--scope",
            "por",
            "--dry-run",
        ]);
        assert_eq!(args.target, "owner/repo");
        assert_eq!(args.name.as_deref(), Some("my-dir"));
        assert_eq!(args.scope, ScopeKind::Por);
        assert!(args.dry_run);
    }

    #[test]
    fn missing_target() {
        let err = parse_err(&["vc-x1", "clone"]);
        assert!(err.contains("TARGET"));
    }

    #[test]
    fn scope_short_flag() {
        let args = parse(&["vc-x1", "clone", "owner/repo", "-s", "por"]);
        assert_eq!(args.scope, ScopeKind::Por);
    }

    #[test]
    fn scope_bot_code_commutative() {
        let args = parse(&["vc-x1", "clone", "owner/repo", "--scope", "bot,code"]);
        assert_eq!(args.scope, ScopeKind::CodeBot);
    }

    #[test]
    fn scope_code_alone_errors() {
        let err = parse_err(&["vc-x1", "clone", "owner/repo", "--scope", "code"]);
        assert!(err.contains("not a valid scope kind"), "got: {err}");
    }

    #[test]
    fn scope_bot_alone_errors() {
        let err = parse_err(&["vc-x1", "clone", "owner/repo", "--scope", "bot"]);
        assert!(err.contains("not a valid scope kind"), "got: {err}");
    }

    #[test]
    fn scope_unknown_errors() {
        let err = parse_err(&["vc-x1", "clone", "owner/repo", "--scope", "xyz"]);
        assert!(err.contains("not recognized"), "got: {err}");
    }

    #[test]
    fn target_path_form_accepted() {
        let args = parse(&["vc-x1", "clone", "/tmp/foo.git"]);
        assert_eq!(args.target, "/tmp/foo.git");
    }

    #[test]
    fn target_relative_path_form_accepted() {
        let args = parse(&["vc-x1", "clone", "./bare.git"]);
        assert_eq!(args.target, "./bare.git");
    }

    // Unit tests for derive_name / resolve_url / derive_session_url
    // live in src/url.rs alongside the lifted functions.
}

//! Shared test helpers for dual-repo integration tests.
//!
//! Provides a `Fixture` that wraps `crate::init::init_with_symlink`
//! plus a per-process unique-tempdir helper so parallel tests don't
//! collide. Lifted out of the `sync` test module (originally inline at
//! `sync.rs:521–560`) so `push`'s tests (0.37.0) and any future
//! subcommand's tests can sit on the same harness without
//! copy-paste drift.
//!
//! Test-only — the whole module is gated at its declaration site via
//! `#[cfg(test)] mod test_helpers;`.

use std::fs;
use std::path::PathBuf;
use std::sync::atomic::{AtomicU64, Ordering};
use std::time::{SystemTime, UNIX_EPOCH};

use crate::common::write_file;
use crate::config::RepoSelector;
use crate::init::{InitArgs, init_with_symlink};
use crate::options_flags::account::AccountFlag;
use crate::options_flags::config::ConfigFlag;
use crate::options_flags::dry_run::DryRunFlag;
use crate::options_flags::private::PrivateFlag;
use crate::options_flags::push_retry::PushRetryFlags;
use crate::options_flags::repo::RepoFlag;
use crate::options_flags::scope::{ScopeFlag, ScopeKind};
use crate::options_flags::use_template::UseTemplateFlag;
use crate::test_tmp_root::{resolve_tmp_root, should_keep_tempdir};

/// Per-process counter so same-nanosecond tempdir collisions yield
/// distinct paths when tests run in parallel.
static COUNTER: AtomicU64 = AtomicU64::new(0);

/// Build a unique tempdir path for a test fixture.
///
/// Combines a nanosecond timestamp with a per-process atomic counter
/// so parallel tests and same-nanosecond collisions both yield
/// distinct paths. Prefix is `vc-x1-test-<tag>-<ts>-<n>` so callers
/// from different subcommand tests stay discoverable in `$TMPDIR`.
pub fn unique_base(tag: &str) -> PathBuf {
    let ts = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
    resolve_tmp_root().join(format!("vc-x1-test-{tag}-{ts}-{n}"))
}

/// Owned dual-repo fixture with RAII cleanup.
///
/// Builds a fresh throwaway dual-repo set under a unique tempdir
/// by driving `init::init_with_symlink` with a path TARGET and
/// `--repo local=<base>` (so config lookup is skipped via the
/// resolve_repo short-circuit). `create_symlink=false` suppresses
/// the `~/.claude/projects/` side effect. Exposes the two repo
/// paths (`work` and `work/.claude`). The tempdir tree is removed
/// when the value is dropped, so a panicking test still cleans up
/// after itself.
pub struct Fixture {
    /// Root tempdir that owns both repos and their bare-git remotes.
    pub base: PathBuf,
    /// Code repo path (`<base>/work`).
    pub work: PathBuf,
    /// Bot session repo path (`<base>/work/.claude`).
    pub claude: PathBuf,
}

impl Fixture {
    /// Build a fresh fixture in a unique tempdir.
    pub fn new(tag: &str) -> Self {
        Self::new_opts(tag, false, None)
    }

    /// Build a fresh fixture with optional pending changes and a
    /// template seed.
    ///
    /// - `with_pending` — after init, write a small file into each
    ///   repo so `@` carries uncommitted changes (useful for
    ///   finalize / push tests).
    /// - `use_template` — `CODE[,BOT]` forwarded to init.
    pub fn new_opts(tag: &str, with_pending: bool, use_template: Option<String>) -> Self {
        let base = unique_base(tag);
        // init refuses to reuse an existing project_dir, so `base`
        // must not exist yet. `unique_base` already guarantees that.
        //
        // Path TARGET = `<base>/work` (workspace destination); the
        // basename ("work") becomes the repo name. `--repo local=<base>`
        // sets the bare-repo parent so the layout mirrors the old
        // `--repo-local <base>` + NAME=`work` shape:
        //   <base>/work/                  (code repo)
        //   <base>/work/.claude/          (bot session repo)
        //   <base>/remote-code.git        (code bare origin)
        //   <base>/remote-claude.git      (bot bare origin)
        let work_path = base.join("work");
        let args = InitArgs {
            target: work_path.to_string_lossy().into_owned(),
            name: None,
            account: AccountFlag::default(),
            repo: RepoFlag {
                repo: Some(RepoSelector {
                    category: "local".to_string(),
                    value: Some(base.to_string_lossy().into_owned()),
                }),
            },
            scope: ScopeFlag {
                scope: ScopeKind::CodeBot,
            },
            private: PrivateFlag::default(),
            dry_run: DryRunFlag::default(),
            push_retry: PushRetryFlags::default(),
            use_template: UseTemplateFlag { use_template },
            config: ConfigFlag::default(),
        };
        init_with_symlink(&args, false).expect("build test fixture via init");

        let work = base.join("work");
        let claude = work.join(".claude");

        if with_pending {
            write_file(&work.join("TODO.md"), "# TODO\n- first feature\n")
                .expect("write pending TODO.md");
            write_file(
                &claude.join("session-notes.md"),
                "# Session notes\n- simulated pending work\n",
            )
            .expect("write pending session-notes.md");
        }

        Fixture { base, work, claude }
    }

    /// Convenience: return both repo paths as a `Vec<PathBuf>`
    /// suitable for `sync_repos` (or any other `&[PathBuf]` API).
    pub fn repos(&self) -> Vec<PathBuf> {
        vec![self.work.clone(), self.claude.clone()]
    }
}

impl Drop for Fixture {
    /// Remove the fixture tree on drop. Best-effort; a failure here
    /// doesn't fail the test. Suppressed when `$VC_X1_TEST_KEEP` is
    /// set — see `test_tmp_root::should_keep_tempdir`.
    fn drop(&mut self) {
        if should_keep_tempdir() {
            eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.base.display());
        } else {
            let _ = fs::remove_dir_all(&self.base);
        }
    }
}

/// Owned single-repo (POR) fixture with RAII cleanup.
///
/// Sibling of `Fixture` for `--scope=por` flows. Drives
/// `init::init_with_symlink` with `ScopeKind::Por` and a path
/// TARGET; `--repo local=<base>` steers the bare origin to
/// `<base>/remote.git` (vs. dual's `remote-code.git` /
/// `remote-claude.git`). No `.claude/` peer, no symlink.
///
/// Field shape differs from `Fixture` — there is no `claude` peer
/// path — so it's a distinct type rather than an `Option<PathBuf>`
/// on `Fixture` (the latter would force every dual-using caller to
/// `.unwrap()` or pattern-match).
pub struct FixturePor {
    /// Root tempdir that owns the repo and its bare-git remote.
    pub base: PathBuf,
    /// POR repo path (`<base>/work`).
    pub work: PathBuf,
}

impl FixturePor {
    /// Build a fresh POR fixture in a unique tempdir.
    pub fn new(tag: &str) -> Self {
        Self::new_with_config(tag, None)
    }

    /// Build a fresh POR fixture, threading `config` through to
    /// `InitArgs` for `--config` variant testing.
    pub fn new_with_config(tag: &str, config: Option<String>) -> Self {
        let base = unique_base(tag);
        // Path TARGET = `<base>/work`; basename ("work") becomes
        // the repo name. `--repo local=<base>` sets the bare-repo
        // parent, producing the layout:
        //   <base>/work/        (POR repo)
        //   <base>/remote.git   (bare origin)
        let work_path = base.join("work");
        let args = InitArgs {
            target: work_path.to_string_lossy().into_owned(),
            name: None,
            account: AccountFlag::default(),
            repo: RepoFlag {
                repo: Some(RepoSelector {
                    category: "local".to_string(),
                    value: Some(base.to_string_lossy().into_owned()),
                }),
            },
            scope: ScopeFlag {
                scope: ScopeKind::Por,
            },
            private: PrivateFlag::default(),
            dry_run: DryRunFlag::default(),
            push_retry: PushRetryFlags::default(),
            use_template: UseTemplateFlag::default(),
            config: ConfigFlag { raw: config },
        };
        init_with_symlink(&args, false).expect("build test fixture via init (POR)");

        let work = base.join("work");
        FixturePor { base, work }
    }
}

impl Drop for FixturePor {
    /// Remove the fixture tree on drop. Best-effort; a failure here
    /// doesn't fail the test. Suppressed when `$VC_X1_TEST_KEEP` is
    /// set — see `test_tmp_root::should_keep_tempdir`.
    fn drop(&mut self) {
        if should_keep_tempdir() {
            eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.base.display());
        } else {
            let _ = fs::remove_dir_all(&self.base);
        }
    }
}

