                    category: "local".to_string(),
                    value: Some(base.to_string_lossy().into_owned()),
                }),
            },
            scope: ScopeFlag {
                scope: ScopeKind::Por,
            },
            provision: ProvisionCommon::default(),
            use_template: UseTemplateFlag::default(),
